## 3️⃣  `pcapng_stubs.c` – C/C++ glue

> **Important:** The file must be compiled as **C++** (e.g. `g++ -c
> pcapng_stubs.c -o pcapng_stubs.o`).  The `extern "C"` wrappers keep the
> symbols name‑mangled in a way the OCaml runtime can find them.

```c
/* ----------------------------------------------------------------------
 *  pcapng_stubs.c – C/C++ glue for libpcapng
 *
 *  Build with:
 *    ocamlc -c pcapng.ml
 *    g++ -I$(OCAML_HOME)/caml -c pcapng_stubs.c -o pcapng_stubs.o
 *    ocamlc -custom -o demo pcapng.cmo pcapng_stubs.o -lpcapng
 * ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>

#include <string>
#include <vector>
#include <stdexcept>

/* --------------------------------------------------------------
 *  Fake libpcapng API – replace this include with the real one.
 * -------------------------------------------------------------- */
#include "libpcapng.hpp"   /* <-- your real header */

/* --------------------------------------------------------------
 *  Helper: convert a native Frame into an OCaml value.
 * -------------------------------------------------------------- */
static value caml_frame_of_native(const Frame &f)
{
  CAMLparam0();
  CAMLlocal3(v_ts, v_data, v_rec_len);
  CAMLlocal1(v_frame);

  /* timestamp – a double */
  v_ts = caml_copy_double(f.ts);

  /* data – a Bytes.t */
  v_data = caml_alloc_initialized_string(f.len, reinterpret_cast<const char*>(f.data));

  /* original length – an int */
  v_rec_len = Val_int((int)f.original_len);

  /* Build the record { ts; data; original_len } */
  v_frame = caml_alloc(3, 0);          /* 3 fields, tag = 0 (record) */
  Store_field(v_frame, 0, v_ts);
  Store_field(v_frame, 1, v_data);
  Store_field(v_frame, 2, v_rec_len);

  CAMLreturn(v_frame);
}

/* --------------------------------------------------------------
 *  Custom block handling – we store a pointer to PcapngReader*
 * -------------------------------------------------------------- */
static void caml_pcapng_finalize(value v)
{
  PcapngReader *r = *(PcapngReader **)Data_custom_val(v);
  delete r;
}

/* Custom operations descriptor – required by OCaml's GC */
static struct custom_operations pcapng_reader_ops = {
  "pcapng_reader_ops",
  caml_pcapng_finalize,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default,
};

/* --------------------------------------------------------------
 *  open_file : string -> t
 * -------------------------------------------------------------- */
CAMLprim value caml_pcapng_open_file(value v_path)
{
  CAMLparam1(v_path);
  CAMLlocal1(v_res);
  const char *path = String_val(v_path);

  /* Try to construct the C++ reader; translate C++ exceptions to OCaml */
  PcapngReader *r = nullptr;
  try {
    r = new PcapngReader(path);
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  }

  /* Allocate a custom block that holds the pointer */
  v_res = caml_alloc_custom(&pcapng_reader_ops, sizeof(PcapngReader *), 0, 1);
  PcapngReader **dst = (PcapngReader **)Data_custom_val(v_res);
  *dst = r;

  CAMLreturn(v_res);
}

/* --------------------------------------------------------------
 *  close : t -> unit
 * -------------------------------------------------------------- */
CAMLprim value caml_pcapng_close(value v_reader)
{
  CAMLparam1(v_reader);
  PcapngReader *r = *(PcapngReader **)Data_custom_val(v_reader);
  delete r;                     /* free the native object               */
  /* Overwrite the pointer with a sentinel so that a later use crashes
     early (instead of silently using freed memory). */
  *(PcapngReader **)Data_custom_val(v_reader) = nullptr;
  CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
 *  iter : (frame -> unit) -> t -> unit
 * -------------------------------------------------------------- */
CAMLprim value caml_pcapng_iter(value v_cb, value v_reader)
{
  CAMLparam2(v_cb, v_reader);
  CAMLlocal1(v_frame);
  PcapngReader *r = *(PcapngReader **)Data_custom_val(v_reader);
  if (r == nullptr) caml_failwith("PcapngReader is already closed");

  /* The loop can be long, so we release the runtime while we are not
     calling back into OCaml.  The runtime is reacquired just before each
     callback. */
  caml_release_runtime_system();
  while (r->has_next()) {
    Frame f = r->next();                     /* C++ fetch */
    caml_acquire_runtime_system();           /* reacquire for callback */
    v_frame = caml_frame_of_native(f);       /* build OCaml record */
    value cb_res = caml_callback_exn(v_cb, v_frame);
    if (Is_exception_result(cb_res)) {
      /* Propagate the exception – the loop stops here. */
      caml_raise(cb_res);
    }
    caml_release_runtime_system();           /* back to “released” state */
  }
  caml_acquire_runtime_system();               /* final reacquire */
  CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
 *  fold : ('a -> frame -> 'a) -> 'a -> t -> 'a
 * -------------------------------------------------------------- */
CAMLprim value caml_pcapng_fold(value v_f, value v_acc, value v_reader)
{
  CAMLparam3(v_f, v_acc, v_reader);
  CAMLlocal2(v_frame, v_new_acc);
  PcapngReader *r = *(PcapngReader **)Data_custom_val(v_reader);
  if (r == nullptr) caml_failwith("PcapngReader is already closed");

  caml_release_runtime_system();
  while (r->has_next()) {
    Frame f = r->next();
    caml_acquire_runtime_system();
    v_frame = caml_frame_of_native(f);
    v_new_acc = caml_callback_exn(v_f, v_acc, v_frame);
    if (Is_exception_result(v_new_acc)) caml_raise(v_new_acc);
    v_acc = v_new_acc;               /* update accumulator */
    caml_release_runtime_system();
  }
  caml_acquire_runtime_system();
  CAMLreturn(v_acc);
}

/* --------------------------------------------------------------
 *  next : t -> frame option
 * -------------------------------------------------------------- */
CAMLprim value caml_pcapng_next(value v_reader)
{
  CAMLparam1(v_reader);
  CAMLlocal2(v_frame, v_some);
  PcapngReader *r = *(PcapngReader **)Data_custom_val(v_reader);
  if (r == nullptr) caml_failwith("PcapngReader is already closed");

  if (!r->has_next()) {
    CAMLreturn(Val_int(0));               /* None */
  }

  Frame f = r->next();
  v_frame = caml_frame_of_native(f);
  v_some = caml_alloc(1, 0);               /* Some */
  Store_field(v_some, 0, v_frame);
  CAMLreturn(v_some);
}
```

--------------------------------------------------------------------
## How it works – a quick walkthrough

1. **Opening** – `open_file` allocates a **custom block** that stores a pointer to a
   `PcapngReader`.  The block gets a finaliser (`caml_pcapng_finalize`) so the
   native object is automatically destroyed when the OCaml value is GC‑collected
   (or when the user calls `close` explicitly).

2. **Frame representation** – The C++ `Frame` struct is turned into an OCaml
   record `{ ts; data; original_len }`.  `data` is a `bytes` value (the most
   efficient way to hold a mutable byte array coming from C).

3. **Iterating** – `caml_pcapng_iter` walks the native iterator.  For each frame
   it:
   * builds an OCaml `frame`,
   * calls the user‑supplied callback with `caml_callback_exn`,
   * checks for an exception and, if present, re‑raises it to abort the loop.

   The runtime is **released** while the native loop runs, which allows other
   OCaml threads to make progress (important for programs that use `Lwt`,
   `Async`, or the multicore runtime).

4. **Folding** – `caml_pcapng_fold` is identical to `iter` except that the
   accumulator is threaded through the callback.  The implementation shows how
   you can pass *two* arguments to a callback (`v_f`, `v_acc`, `v_frame`).

5. **Single‑step access** – `next` returns an `option` so that OCaml code can
   pull frames manually if they want a “pull‑based” API instead of a callback.

--------------------------------------------------------------------
## Using the binding (example)

```ocaml
(* demo.ml ---------------------------------------------------------- *)
let () =
  let reader = Pcapng.open_file "sample.pcapng" in
  (* 1. Simple iteration *)
  Pcapng.iter (fun frame ->
      Printf.printf "ts=%f len=%d\n%!"
        frame.ts (Bytes.length frame.data)
    ) reader;

  (* 2. Folding – count packets larger than 1000 bytes *)
  let big_cnt =
    Pcapng.fold (fun acc frame ->
        if Bytes.length frame.data > 1000 then acc + 1 else acc
      ) 0 reader
  in
  Printf.printf "big packets = %d\n%!" big_cnt;

  (* 3. Pull‑based API *)
  let rec dump () =
    match Pcapng.next reader with
    | None -> ()
    | Some f ->
        Printf.printf "next: %f %d\n%!" f.ts (Bytes.length f.data);
        dump ()
  in
  dump ();

  Pcapng.close reader
```

Compile:

```sh
ocamlopt -c pcapng.ml
g++ -I$(ocamlc -where) -c pcapng_stubs.c -o pcapng_stubs.o
ocamlopt -o demo pcapng.cmx pcapng_stubs.o -lpcapng
```

Now `./demo` will walk the file, invoking the user‑supplied OCaml code for each
frame – exactly the pattern you asked for.  

Feel free to replace the mock `libpcapng.hpp` includes with the real header and
adjust the `Frame` field names if they differ. The rest of the binding stays
the same. Happy hacking!
